func sortByName[T orderedByName](direction string, results []T) {

	if direction == ascendantSorting {
		sort.Slice(results, func(i, j int) bool {
			return results[i].name() < results[j].name()
		})

		return
	}

	sort.Slice(results, func(i, j int) bool {
		return results[i].name() > results[j].name()
	})
}
